sql:
SELECT COUNT(DISTINCT s.study_name) AS unique_study_names
FROM studies s
WHERE s.study_name NOT IN (
  SELECT d.dataset_name
  FROM datasets d
);

SELECT role_name
FROM user_roles
WHERE permissions LIKE '%create_dataset%';

external_knowledge:
- 'keys to the treasure chest of datasets' refers to having read permissions on at least one dataset;
- 'pen to write on the canvas of samples' refers to having write permissions on at least one sample;
- 'part of the secret society of studies' refers to being involved in at least one study;
- 'unique users' means the count of distinct user IDs.
